            throw new RuntimeException("Failed to upload file to OSS. Error Message: " + e.getErrorMessage(), e);
        } catch (ClientException e) {
            // Caught when network issues occur or client configuration is invalid
            throw new RuntimeException("Client error occurred while uploading to OSS. Error Message: " + e.getMessage(), e);
        }
    }

    /**
     * Constructs the complete access URL for the uploaded object.
     *
     * @param objectName The object name in OSS.
     * @return The formatted URL string.
     */
    private String buildAccessUrl(String objectName) {
        String scheme = "https://";
        String cleanEndpoint = endpoint;

        if (endpoint.toLowerCase().startsWith("http://")) {
            scheme = "http://";
            cleanEndpoint = endpoint.substring(7);
        } else if (endpoint.toLowerCase().startsWith("https://")) {
            cleanEndpoint = endpoint.substring(8);
        }

        // Remove leading slash from objectName to avoid double slashes in the URL
        String cleanObjectName = objectName.startsWith("/") ? objectName.substring(1) : objectName;

        return scheme + bucketName + "." + cleanEndpoint + "/" + cleanObjectName;
    }

    /**
     * Shuts down the OSS client and releases resources.
     * Should be called when the service instance is no longer needed.
     */
    @Override
    public void close() {
        if (this.ossClient != null) {
            this.ossClient.shutdown();
        }
    }
}
